// ─── INJECT STYLES ────────────────────────────────────────────────
const StyleTag = () => {
  useEffect(() => {
    const tag = document.createElement("style");
    tag.innerHTML = styles;
    document.head.appendChild(tag);
    return () => document.head.removeChild(tag);
  }, []);
  return null;
};

