// ─── LOGIN PAGE ───────────────────────────────────────────────────
function LoginPage({ onLogin, onAdminLogin }) {
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [loading, setLoading] = useState(false);
  const [alert, setAlert] = useState(null);

  async function handleLogin() {
    if (!username || !password) { setAlert({ type: "err", msg: "Please fill in all fields." }); return; }
    if (username === ADMIN_USER && password === ADMIN_PASS) { onAdminLogin(); return; }
    setLoading(true); setAlert(null);
    try {
      const res = await API.login({ username, password });
      const data = await res.json();
      if (res.ok) { onLogin(data); }
      else { setAlert({ type: "err", msg: data.message || "Invalid credentials." }); }
    } catch {
      setAlert({ type: "err", msg: "Cannot reach server. Please try again." });
    } finally { setLoading(false); }
  }

  return (
    <div className="page">
      <div className="auth-wrap">
        <div className="auth-card">
          <div className="auth-logo">
            <div className="cring">🗺</div>
            <h2>SILICON MULTIVERSE</h2>
            <p>TREASURE HUNT · ROUND 3</p>
          </div>
          <div className="fld">
            <label>USERNAME</label>
            <input type="text" value={username} onChange={e => setUsername(e.target.value)}
              placeholder="Enter your username" onKeyDown={e => e.key === "Enter" && handleLogin()} />
          </div>
          <div className="fld">
            <label>PASSWORD</label>
            <input type="password" value={password} onChange={e => setPassword(e.target.value)}
              placeholder="Enter your password" onKeyDown={e => e.key === "Enter" && handleLogin()} />
          </div>
          <button className="sb" onClick={handleLogin} disabled={loading}>
            {loading ? "AUTHENTICATING..." : "BEGIN HUNT →"}
          </button>
          {alert && <div className={`alert ${alert.type}`}>{alert.msg}</div>}
        </div>
      </div>
    </div>
  );
}

// ─── SECTION CARD ─────────────────────────────────────────────────
function SectionCard({ section, onComplete, isLocked }) {
  const [values, setValues] = useState(
    section.inputType === "multi" ? section.blanks.map(() => "") : [""]
  );
  const [error, setError] = useState(null);
  const [correct, setCorrect] = useState(false);

  function updateValue(i, v) {
    const n = [...values]; n[i] = v; setValues(n);
  }

  function checkAnswer() {
    if (section.inputType === "single") {
      if (values[0].trim().toLowerCase() === section.answer.toLowerCase()) {
        setCorrect(true); setError(null); onComplete(section.id);
      } else { setError("Incorrect answer. Try again!"); }
    } else {
      const allOk = section.blanks.every((b, i) =>
        values[i].trim().toLowerCase() === b.answer.toLowerCase()
      );
      if (allOk) { setCorrect(true); setError(null); onComplete(section.id); }
      else { setError("One or more answers are incorrect. Check and try again!"); }
    }
  }

  if (isLocked) {
    return (
      <div style={{
        background:"rgba(10,22,40,.6)", border:"1px solid rgba(0,212,255,0.07)",
        borderRadius:"16px", padding:"28px", opacity:0.4,
        display:"flex", alignItems:"center", gap:"16px"
      }}>
        <span style={{fontSize:"24px"}}>🔒</span>
        <div>
          <div style={{fontFamily:"'Orbitron',sans-serif", fontSize:"13px", color:"var(--tx2)", letterSpacing:"2px"}}>{section.title}</div>
          <div style={{fontSize:"12px", color:"var(--tx2)", marginTop:"4px"}}>Complete previous section to unlock</div>
        </div>
      </div>
    );
  }

  return (
    <div style={{
      background:"linear-gradient(145deg,rgba(10,22,40,.96),rgba(13,31,60,.9))",
      border:`1px solid ${correct ? "var(--c3)" : "var(--bd)"}`,
      borderRadius:"16px", overflow:"hidden",
      boxShadow: correct ? "0 0 24px rgba(0,255,163,0.12)" : "none",
      transition:"all .3s"
    }}>
      <div style={{display:"flex", minHeight:"380px"}}>

        {/* LEFT: Clue Panel */}
        <div style={{
          width:"40%", minWidth:"260px",
          background:"rgba(0,212,255,0.03)",
          borderRight:"1px solid rgba(0,212,255,0.1)",
          padding:"28px 22px", overflowY:"auto"
        }}>
          <div style={{
            fontFamily:"'Share Tech Mono',monospace", fontSize:"10px",
            color:"var(--c1)", letterSpacing:"3px", marginBottom:"14px"
          }}>⚡ {section.title}</div>
          <div style={{
            fontSize:"12px", color:"var(--tx2)",
            lineHeight:"1.85", whiteSpace:"pre-wrap"
          }}>{section.clue}</div>
        </div>

        {/* RIGHT: Answer */}
        <div style={{flex:1, padding:"28px 24px", display:"flex", flexDirection:"column", justifyContent:"center"}}>
          {correct ? (
            <div style={{textAlign:"center", padding:"20px"}}>
              <div style={{fontSize:"48px", marginBottom:"16px"}}>✅</div>
              <div style={{
                fontFamily:"'Orbitron',sans-serif", fontSize:"14px",
                color:"var(--c3)", letterSpacing:"2px", marginBottom:"12px"
              }}>SECTION COMPLETE</div>
              <div style={{fontSize:"13px", color:"var(--tx2)", lineHeight:"1.7"}}>
                {section.successMessage}
              </div>
            </div>
          ) : (
            <>
              <div style={{
                fontFamily:"'Share Tech Mono',monospace", fontSize:"10px",
                color:"var(--c2)", letterSpacing:"2px", marginBottom:"20px"
              }}>
                {section.inputType === "multi" ? "FILL IN ALL BLANKS" : "ENTER YOUR ANSWER"}
              </div>

              {section.inputType === "single" ? (
                <input
                  type="text"
                  value={values[0]}
                  onChange={e => updateValue(0, e.target.value)}
                  onKeyDown={e => e.key === "Enter" && checkAnswer()}
                  placeholder={section.placeholder}
                  style={{
                    width:"100%", background:"rgba(0,0,0,.5)",
                    border:"1px solid var(--bd)", borderRadius:"8px",
                    padding:"12px 16px", color:"var(--tx)",
                    fontFamily:"'Share Tech Mono',monospace",
                    fontSize:"14px", outline:"none", marginBottom:"16px"
                  }}
                />
              ) : (
                <div style={{display:"flex", flexDirection:"column", gap:"10px", marginBottom:"16px"}}>
                  {section.blanks.map((b, i) => (
                    <div key={i}>
                      <div style={{fontSize:"10px", color:"var(--tx2)", letterSpacing:"1px", marginBottom:"5px"}}>{b.label}</div>
                      <input
                        type="text"
                        value={values[i]}
                        onChange={e => updateValue(i, e.target.value)}
                        placeholder={b.placeholder}
                        style={{
                          width:"100%", background:"rgba(0,0,0,.5)",
                          border:"1px solid var(--bd)", borderRadius:"8px",
                          padding:"10px 14px", color:"var(--tx)",
                          fontFamily:"'Share Tech Mono',monospace",
                          fontSize:"13px", outline:"none"
                        }}
                      />
                    </div>
                  ))}
                </div>
              )}

              {error && <div className="alert err" style={{marginBottom:"12px"}}>{error}</div>}
              <button className="sb" onClick={checkAnswer}>SUBMIT ANSWER →</button>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

// ─── HUNT PAGE ────────────────────────────────────────────────────
function HuntPage({ user, token }) {
  const [completedSections, setCompletedSections] = useState([]);
  const [finished, setFinished] = useState(false);

  function handleComplete(sectionId) {
    const updated = [...completedSections, sectionId];
    setCompletedSections(updated);
    if (updated.length === SECTIONS.length) {
      setTimeout(() => setFinished(true), 1400);
      try { API.submitHunt({ completed: true, teamName: user?.teamName }, token); } catch {}
    }
  }

  if (finished) {
    return (
      <div className="page">
        <div className="res-wrap">
          <div className="res-ring">
            <span style={{fontSize:"52px"}}>🏆</span>
          </div>
          <div className="res-title">HUNT COMPLETE!</div>
          <div className="res-msg" style={{
            maxWidth:"500px", textAlign:"center", lineHeight:"1.9",
            color:"var(--tx)", fontSize:"16px", marginBottom:"12px"
          }}>
            Now run back to the event hall and show the judges you have successfully finished the treasure hunt!
          </div>
          <div className="res-xp">🎉 All sections decoded · Team {user?.teamName}</div>
        </div>
      </div>
    );
  }

  return (
    <div className="page">
      <div className="dh">
        <div className="ep">🗺 SILICON MULTIVERSE · TREASURE HUNT</div>
        <h2>ROUND 3</h2>
        <p>Team: <strong style={{color:"var(--c1)"}}>{user?.teamName}</strong> · Complete all sections in order</p>
      </div>

      <div style={{maxWidth:"1000px", margin:"0 auto", padding:"32px 24px", display:"flex", flexDirection:"column", gap:"20px"}}>

        {/* Progress tracker */}
        <div style={{display:"flex", alignItems:"center", gap:"8px", marginBottom:"4px"}}>
          {SECTIONS.map((s, i) => (
            <div key={i} style={{display:"flex", alignItems:"center", gap:"8px"}}>
              <div style={{
                width:"32px", height:"32px", borderRadius:"50%",
                border:`2px solid ${completedSections.includes(s.id) ? "var(--c3)" : "var(--bd)"}`,
                background: completedSections.includes(s.id) ? "rgba(0,255,163,0.15)" : "transparent",
                display:"flex", alignItems:"center", justifyContent:"center",
                fontFamily:"'Orbitron',sans-serif", fontSize:"11px",
                color: completedSections.includes(s.id) ? "var(--c3)" : "var(--tx2)",
                transition:"all .3s"
              }}>
                {completedSections.includes(s.id) ? "✓" : i + 1}
              </div>
              {i < SECTIONS.length - 1 && (
                <div style={{
                  width:"40px", height:"2px",
                  background: completedSections.includes(s.id) ? "var(--c3)" : "rgba(0,212,255,0.15)",
                  transition:"all .3s"
                }} />
              )}
            </div>
          ))}
          <div style={{marginLeft:"8px", fontFamily:"'Share Tech Mono',monospace", fontSize:"11px", color:"var(--tx2)"}}>
            {completedSections.length} / {SECTIONS.length} complete
          </div>
        </div>

        {SECTIONS.map((section, i) => (
          <SectionCard
            key={section.id}
            section={section}
            onComplete={handleComplete}
            isLocked={i > 0 && !completedSections.includes(SECTIONS[i - 1].id)}
          />
        ))}
      </div>
    </div>
  );
}

// ─── ADMIN PAGE ───────────────────────────────────────────────────
function AdminPage({ token }) {
  const [teams, setTeams] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    API.getProgress(token)
      .then(r => r.json())
      .then(d => setTeams(d.teams || []))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, [token]);

  return (
    <div className="page">
      <div className="page-header">
        <h2>ADMIN — HUNT PROGRESS</h2>
        <p>Live tracking of all teams in Round 3</p>
      </div>
      <div className="admin-wrap">
        <div className="admin-section">
          <h3>TEAM PROGRESS ({teams.length} teams)</h3>
          {loading ? (
            <div style={{color:"var(--tx2)", padding:"20px"}}>Loading...</div>
          ) : !teams.length ? (
            <div style={{color:"var(--tx2)", padding:"20px"}}>No teams have started yet.</div>
          ) : (
            teams.map((t, i) => (
              <div className="user-row" key={i}>
                <div className="user-name">{t.teamName}</div>
                <div style={{display:"flex", gap:"6px"}}>
                  {[1, 2, 3].map(s => (
                    <div key={s} style={{
                      padding:"3px 10px", borderRadius:"12px", fontSize:"11px",
                      fontFamily:"'Share Tech Mono',monospace",
                      background: t.completedSections?.includes(s) ? "rgba(0,255,163,.1)" : "rgba(255,255,255,.04)",
                      border: `1px solid ${t.completedSections?.includes(s) ? "rgba(0,255,163,.4)" : "rgba(255,255,255,.08)"}`,
                      color: t.completedSections?.includes(s) ? "var(--c3)" : "var(--tx2)"
                    }}>S{s}</div>
                  ))}
                </div>
                <div className={`role-badge ${t.completedSections?.length === 3 ? "role-leader" : "role-member"}`}>
                  {t.completedSections?.length === 3 ? "FINISHED" : `${t.completedSections?.length || 0}/3`}
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
}

// ─── APP ROOT ─────────────────────────────────────────────────────
export default function App() {
  const [page, setPage] = useState("login");
  const [user, setUser] = useState(null);
  const [token, setToken] = useState(null);
  const [isAdmin, setIsAdmin] = useState(false);

  function handleLogin(data) { setUser(data.user); setToken(data.token); setPage("hunt"); }
  function handleAdminLogin() { setIsAdmin(true); setToken("admin"); setPage("admin"); }
  function handleLogout() { setUser(null); setToken(null); setIsAdmin(false); setPage("login"); }

  function renderPage() {
    switch (page) {
      case "login": return <LoginPage onLogin={handleLogin} onAdminLogin={handleAdminLogin} />;
      case "hunt":  return <HuntPage user={user} token={token} />;
      case "admin": return <AdminPage token={token} />;
      default:      return <LoginPage onLogin={handleLogin} onAdminLogin={handleAdminLogin} />;
    }
  }

  return (
    <>
      <StyleTag />
      <div className="app-bg" />
      <Header user={user || (isAdmin ? { username: "Admin" } : null)} onLogout={handleLogout} />
      {renderPage()}
    </>
  );
}
